{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/TensaiGunshiNiNaro.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class TensaiGunshiNiNaro < Base\n      # ゲームシステムの識別子\n      ID = 'TensaiGunshiNiNaro'\n\n      # ゲームシステム名\n      NAME = '天才軍師になろう'\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = 'てんさいくんしになろう'\n\n      # ダイスボットの使い方\n      HELP_MESSAGE = <<~MESSAGETEXT\n        ・行為判定\n        TN6…「有利」を得ていない場合、6面ダイスを2つ振って判定します。\n        TN10…「有利」を得ている場合、10面ダイスを2つ振って判定します。\n        不調 気づかぬうちの不満【C】…このセッションの間、「4」の出目を出しても判定は成功になりません。数字の後ろに【C】をつけます。\n        　例）TN6C\n        軍師スキル 〇〇サポート【S】…決戦フェイズの判定中「3」の出目を出しても判定に成功します。数字の後ろに【S】をつけます。\n        　例）TN6S\n        英傑スキル/武人 煌めく刃【B】…決戦フェイズの判定中「3」の出目を出しても判定に成功となり、スペシャルが発生します。数字の後ろに【B】をつけます。\n        　例）TN6B\n        英傑スキル/武人 力ずく…その判定のサイコロをすべて振った後、[使用者の【攻撃力】]個サイコロを振る。先頭に使用者の【攻撃力】をつけます。\n        　例）4TN6\n        英傑スキル/武人 必殺の剣【D】…《戦技》を使用している判定中「4」「5」の出目を出してもスペシャルが発生します。数字の後ろに【D】をつけます。\n        　例）TN6K\n        英傑スキル/武人 二刀流【T】…「攻撃」のスキルの判定中「2」の出目を出しても判定に成功となり、同じ出目のサイコロが2つ以上出ているとスペシャルが発生します。数字の後ろに【T】をつけます。\n        　例）TN6T\n        英傑スキル/カリスマ 御身のためならば【Y】…「交流」「スカウト」の判定中「3」の出目を出しても判定に成功となり、スペシャルが発生します。数字の後ろに【Y】をつけます。\n        　例）TN6Y\n        英傑スキル/弓取り 愛用の弓【A】…「攻撃」のスキルの判定中「3」の出目を出しても判定に成功となり、スペシャルが発生します。数字の後ろに【A】をつけます。\n        　例）TN6A\n        英傑スキル/ヤンキー&マイルドヤンキー その辺の物を武器に【C】…「4」の出目を出しても判定は成功になりません。数字の後ろに【C】をつけます。\n        　例）TN6C\n        英傑スキル/ヤンキー&マイルドヤンキー 熱血判定【C】…「4」の出目を出しても判定は成功になりません。数字の後ろに【C】をつけます。\n        　例）TN6C\n        英傑スキル/英傑汎用 凄腕エージェント【A】…活動フェイズの判定中「3」の出目を出しても判定に成功となり、スペシャルが発生します。数字の後ろに【A】をつけます。\n        　例）TN6A\n        数字の後ろに複数のコマンドを追加できます。\n        　例）TN10CYA\n        ・ダメージ計算 xDM+y>=t\n        　[ダメージ計算]を行う。成否と【HP】の減少量を表示する。\n        　x: 6面ダイス数\n        　y: 補正値（省略可能）\n        　t: 防御力\n        ・各種表\n        関係決定表 RELA\n        平時天才軍師表 PTGS\n        平時英傑表 PTHE\n        スカウト表 SCOU\n        変調表 BDST\n      MESSAGETEXT\n\n      def initialize(command)\n        super(command)\n\n        @d66_sort_type = D66SortType::ASC\n        @round_type = RoundType::FLOOR\n      end\n\n      register_prefix('\\d*TN(6|10)[ABCKSTY]*', '\\d+DM')\n\n      def eval_game_system_specific_command(command)\n        roll_judge(command) || roll_damage(command) || roll_tables(command, self.class::TABLES)\n      end\n\n      private\n\n      # 行為判定\n      def roll_judge(command)\n        m = /^(\\d*)TN(6|10)([ABCKSTY]*)$/.match(command)\n        unless m\n          return nil\n        end\n\n        # 成功となる出目\n        success_dices = [4, 5, 6, 7, 8, 9, 10]\n\n        # スペシャルとなる出目\n        special_dices = [6, 10]\n\n        # ファンブルとなる出目\n        fumble_dices = [1]\n\n        # 有利\n        advantage = m[2] == \"10\"\n\n        # 不調 気づかぬうちの不満\n        complaints = m[3].include?(\"C\")\n\n        # 軍師スキル 〇〇サポート\n        support = m[3].include?(\"S\")\n\n        # 英傑スキル/武人 煌めく刃\n        blade = m[3].include?(\"B\")\n\n        # 英傑スキル/武人 必殺の剣\n        killer = m[3].include?(\"K\")\n\n        # 英傑スキル/武人 二刀流\n        twin = m[3].include?(\"T\")\n\n        # 英傑スキル/カリスマ 御身のためならば\n        you = m[3].include?(\"Y\")\n\n        # 英傑スキル/弓取り 愛用の弓\n        # 英傑スキル/英傑汎用 凄腕エージェント\n        agent = m[3].include?(\"A\")\n\n        # 二刀流の適用時\n        if twin\n          # 成功となる出目に2を追加\n          success_dices.push(2)\n        end\n\n        # 〇〇サポート、煌めく刃、愛用の弓、御身のためならば、凄腕エージェントいずれかの適用時\n        if support | blade | you | agent\n          # 成功となる出目に3を追加\n          success_dices.push(3)\n        end\n\n        # 煌めく刃、御身のためならば、愛用の弓、凄腕エージェントいずれかの適用時\n        if blade | you | agent\n          # スペシャルとなる出目に3を追加\n          special_dices.push(3)\n        end\n\n        # 必殺の剣の適用時\n        if killer\n          # スペシャルとなる出目に4，5を追加\n          special_dices.push(4)\n          special_dices.push(5)\n        end\n\n        # 気づかぬうちの不満適用時\n        if complaints\n          # 成功となる出目から4を削除\n          success_dices.delete(4)\n        end\n\n        # 英傑スキル/武人 力ずく\n        times = 2 + m[1].to_i\n        dice_size = advantage ? 10 : 6\n        dice_list = @randomizer.roll_barabara(times, dice_size)\n\n        texts = []\n        is_critical = false\n        is_fumble = false\n        is_success = false\n\n        # スペシャルとなる出目を含む、または、二刀流の適用時かつ同じ出目のサイコロが2つ以上出ている場合\n        if !dice_list.intersection(special_dices).empty? | (twin & (dice_list.count != dice_list.uniq.count))\n          # クリティカルフラグを立てる\n          is_critical = true\n          # スペシャルのシステムメッセージを追加\n          texts.push(translate(\"TensaiGunshiNiNaro.JUDGE.critical\"))\n          special_effects = []\n          # 通常時の追加効果\n          special_effects.push(translate(\"TensaiGunshiNiNaro.NORMAL.critical\"))\n          # 英傑スキル/武人 煌めく刃による追加効果\n          special_effects.push(translate(\"TensaiGunshiNiNaro.BLADE.critical\")) if blade\n          # 英傑スキル/カリスマ 御身のためならばによる追加効果\n          special_effects.push(translate(\"TensaiGunshiNiNaro.YOU.critical\")) if you\n          # 追加効果を結合してカッコ内に格納\n          texts.push(\"（\#{special_effects.join('')}）\")\n        end\n\n        # ファンブルとなる出目を含む場合\n        unless dice_list.intersection(fumble_dices).empty?\n          # ファンブルフラグを立てる\n          is_fumble = true\n          # ファンブルのシステムメッセージを追加\n          texts.push(translate(\"TensaiGunshiNiNaro.JUDGE.fumble\"))\n          # ファンブルの追加効果をカッコ内に格納\n          texts.push(\"（\#{translate('TensaiGunshiNiNaro.NORMAL.fumble')}）\")\n        end\n\n        if dice_list.intersection(success_dices).empty?\n          # 成功となる出目を含まない場合\n          # 失敗の汎用メッセージを追加\n          texts.push(translate(\"failure\"))\n        else\n          # 成功となる出目を含む場合\n          # 成功フラグを立てる\n          is_success = true\n          # 成功の汎用メッセージを追加\n          texts.push(translate(\"success\"))\n        end\n\n        return Result.new.tap do |r|\n          # テキストを整形\n          r.text = \"\#{command} ＞ [\#{dice_list.join(',')}] ＞ \#{texts.join('')}\"\n          # 各種成否を格納\n          r.condition = is_success\n          r.critical = is_critical\n          r.fumble = is_fumble\n        end\n      end\n\n      # ダメージ計算\n      def roll_damage(command)\n        parser = Command::Parser.new(\"DM\", round_type: @round_type)\n                                .has_prefix_number\n                                .restrict_cmp_op_to(:>=)\n        parsed = parser.parse(command)\n        unless parsed\n          return nil\n        end\n\n        text = ''\n        is_success = false\n\n        # ダメージ計算\n        damage = @randomizer.roll_sum(parsed.prefix_number, 6) + parsed.modify_number\n        # HP減少量計算\n        dec = (damage / parsed.target_number).floor\n\n        # HP減少量の最大値は3\n        dec = 3 if dec > 3\n\n        if dec > 0\n          # HPを減らせた場合\n          # 成功フラグを立てる\n          is_success = true\n          # 成功メッセージを追加\n          text = translate(\"TensaiGunshiNiNaro.DAMAGE.success\", damage: damage.to_s, dec: dec.to_s)\n        else\n          # 失敗メッセージを追加\n          text = translate(\"TensaiGunshiNiNaro.DAMAGE.failure\", damage: damage.to_s)\n        end\n\n        return Result.new.tap do |r|\n          # テキストを整形\n          r.text = \"\#{command} ＞ \#{damage} ＞ \#{text}\"\n          # 各種成否を格納\n          r.condition = is_success\n        end\n      end\n\n      class << self\n        private\n\n        def translate_tables(locale)\n          {\n            \"RELA\" => DiceTable::D66Table.from_i18n(\"TensaiGunshiNiNaro.table.RELA\", locale),\n            \"PTGS\" => DiceTable::D66Table.from_i18n(\"TensaiGunshiNiNaro.table.PTGS\", locale),\n            \"PTHE\" => DiceTable::D66Table.from_i18n(\"TensaiGunshiNiNaro.table.PTHE\", locale),\n            \"SCOU\" => DiceTable::D66Table.from_i18n(\"TensaiGunshiNiNaro.table.SCOU\", locale),\n            \"BDST\" => DiceTable::Table.from_i18n(\"TensaiGunshiNiNaro.table.BDST\", locale),\n          }\n        end\n      end\n\n      TABLES = translate_tables(:ja_jp)\n\n      register_prefix(TABLES.keys)\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:TensaiGunshiNiNaro>", "initialize", "command", "self", "@d66_sort_type", "D66SortType::ASC", "D66SortType", "@round_type", "RoundType::FLOOR", "RoundType", "register_prefix", "eval_game_system_specific_command", "$ret_or_1", "$ret_or_2", "roll_judge", "roll_damage", "roll_tables", "class::TABLES", "class", "private", "m", "match", "success_dices", "4", "5", "6", "7", "8", "9", "10", "special_dices", "fumble_dices", "1", "advantage", "[]", "2", "==", "complaints", "3", "include?", "support", "blade", "killer", "twin", "you", "agent", "push", "|", "delete", "times", "+", "to_i", "dice_size", "dice_list", "@randomizer", "roll_barabara", "texts", "is_critical", "is_fumble", "is_success", "intersection", "empty?", "!", "&", "count", "!=", "uniq", "translate", "special_effects", "join", "tap", "Result", "new", "block in roll_judge", "r", "block (2 levels) in roll_judge", "text=", "condition=", "critical=", "fumble=", "parser", "Command::Parser", "Command", "has_prefix_number", "restrict_cmp_op_to", "parsed", "parse", "text", "damage", "roll_sum", "prefix_number", "modify_number", "dec", "/", "target_number", "floor", ">", "0", "to_s", "block in roll_damage", "block (2 levels) in roll_damage", "translate_tables", "locale", "DiceTable::D66Table", "DiceTable", "from_i18n", "DiceTable::Table", "TABLES", "keys", "Base"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QAEE,8BAAKA,oBAAL;QAGA,gCAAOA,UAAP;QAGA,oCAAWA,aAAX;QAGA,wCACNA,SADqB,GAErBA,sCAFqB,GAGrBA,uCAHqB,GAIrBA,oEAJqB,GAKrBA,WALqB,GAMrBA,iEANqB,GAOrBA,WAPqB,GAQrBA,8EARqB,GASrBA,WATqB,GAUrBA,yEAVqB,GAWrBA,WAXqB,GAYrBA,4EAZqB,GAarBA,WAbqB,GAcrBA,kGAdqB,GAerBA,WAfqB,GAgBrBA,wFAhBqB,GAiBrBA,WAjBqB,GAkBrBA,iFAlBqB,GAmBrBA,WAnBqB,GAoBrBA,2EApBqB,GAqBrBA,WArBqB,GAsBrBA,sEAtBqB,GAuBrBA,WAvBqB,GAwBrBA,oFAxBqB,GAyBrBA,WAzBqB,GA0BrBA,yBA1BqB,GA2BrBA,cA3BqB,GA4BrBA,oBA5BqB,GA6BrBA,kCA7BqB,GA